SELECT 
  v.category, v.emoji, tp.id as product_id, v.mode, v.temp, v.time, v.translations::jsonb, true, v.display_order
FROM (
  VALUES
    ('airfryeroven', '🍗', 'Air Fry', '375°F (190°C)', '25-30 minutes',
     '{"en":{"title":"Oven-Fried Buttermilk Chicken","description":"Crispy, golden fried chicken with juicy buttermilk-marinated meat — no deep frying needed.","ingredients":["2 bone-in chicken pieces (thighs or breast)","1 cup buttermilk","½ tsp paprika powder","¼ tsp garlic powder","½ tsp black pepper","½ cup all-purpose flour","Cooking spray or light oil spray"],"directions":["Coat each chicken piece evenly with the seasoned flour mixture.","Place chicken pieces into the air fryer basket in a single layer.","Cook at 375°F (190°C) for 25-30 minutes, flipping halfway through.","Cook until internal temperature reaches 165°F (74°C)."],"tips":["Do not stack pieces on top of each other — this prevents even cooking and crisping.","For extra crispy results, give chicken pieces a quick spray with cooking spray or a light coat of oil."]},"es":{"title":"Pollo Frito con Suero de Leche Crocante","description":"Pollo frito crujiente y dorado con carne jugosa marinada en suero de leche — sin freír en aceite.","ingredients":["2 piezas de pollo con hueso (muslos o pechuga)","1 taza de suero de leche","½ cdta de pimentón en polvo","¼ cdta de ajo en polvo","½ cdta de pimienta negra","½ taza de harina de trigo","Spray de cocina o aceite ligero"],"directions":["Cubra cada pieza de pollo uniformemente con la mezcla de harina sazonada.","Coloque las piezas de pollo en la canasta de la freidora de aire en una sola capa.","Cocine a 190°C durante 25-30 minutos, volteando a la mitad.","Cocine hasta que la temperatura interna alcance 74°C."],"tips":["No apile las piezas — esto impide una cocción uniforme.","Para resultados extra crujientes, rocíe las piezas con spray de cocina."]},"fr":{"title":"Poulet Frit au Babeurre Croustillant","description":"Poulet frit croustillant et doré avec une viande juteuse marinée au babeurre — sans friture.","ingredients":["2 morceaux de poulet avec os (cuisses ou blanc)","1 tasse de babeurre","½ càc de paprika en poudre","¼ càc d ail en poudre","½ càc de poivre noir","½ tasse de farine tout usage","Spray de cuisson ou huile légère"],"directions":["Enrobez chaque morceau de poulet uniformément avec le mélange de farine assaisonnée.","Placez les morceaux de poulet dans le panier de la friteuse en une seule couche.","Cuire à 190°C pendant 25-30 minutes, en retournant à mi-cuisson.","Cuire jusqu à ce que la température interne atteigne 74°C."],"tips":["N empilez pas les morceaux — cela empêche une cuisson uniforme.","Pour des résultats extra croustillants, vaporisez les morceaux avec un spray de cuisson."]},"ja":{"title":"オーブンフライドバターミルクチキン","description":"バターミルクに漬け込んだジューシーな鶏肉を、揚げずにカリッと黄金色に仕上げました。","ingredients":["骨付き鶏肉（もも肉または胸肉）2枚","バターミルク 1カップ","パプリカパウダー 小さじ1/2","ガーリックパウダー 小さじ1/4","黒コショウ 小さじ1/2","薄力粉 1/2カップ","クッキングスプレーまたは軽い油"],"directions":["鶏肉に味付けした小麦粉をまんべんなくまぶす。","鶏肉をエアフライヤーバスケットに重ならないように並べる。","375°F（190°C）で25-30分調理し、途中で裏返す。","内部温度が165°F（74°C）に達するまで調理する。"],"tips":["重ねて置かないでください — 均一な調理とカリッとした仕上がりを妨げます。","よりカリカリに仕上げたい場合は、クッキングスプレーを軽く吹きかけてください。"]},"pt":{"title":"Frango Frito Crocante com Buttermilk","description":"Frango frito crocante e dourado com carne suculenta marinada em buttermilk — sem fritura em óleo.","ingredients":["2 pedaços de frango com osso (coxas ou peito)","1 xícara de buttermilk","½ colher de chá de páprica em pó","¼ colher de chá de alho em pó","½ colher de chá de pimenta preta","½ xícara de farinha de trigo","Spray de cozinha ou óleo leve"],"directions":["Cubra cada pedaço de frango uniformemente com a mistura de farinha temperada.","Coloque os pedaços de frango na cesta da fritadeira em uma única camada.","Cozinhe a 190°C por 25-30 minutos, virando na metade do tempo.","Cozinhe até que a temperatura interna atinja 74°C."],"tips":["Não empilhe os pedaços — isso impede o cozimento uniforme.","Para resultados extra crocantes, borrife os pedaços com spray de cozinha."]},"zh":{"title":"免炸酪乳脆皮炸鸡","description":"金黄酥脆的炸鸡，酪乳腌制后肉质多汁鲜嫩 — 无需油炸。","ingredients":["带骨鸡肉 2块（鸡腿或鸡胸）","酪乳 1杯","红椒粉 1/2茶匙","大蒜粉 1/4茶匙","黑胡椒 1/2茶匙","中筋面粉 1/2杯","烹饪喷雾或少量食用油"],"directions":["将鸡肉均匀裹上调好味的面粉。","将鸡肉单层放入空气炸锅炸篮中。","以375°F（190°C）烹制25-30分钟，中途翻面。","烹至内部温度达165°F（74°C）即可。"],"tips":["不要叠放鸡肉 — 否则会影响均匀受热和酥脆度。","想要更酥脆，可在烹制前给鸡肉喷一层薄薄的烹饪喷雾。"]}}',
     1),
    ('airfryeroven', '🧄', 'Toast', '400°F (205°C)', '6-8 minutes',
     '{"en":{"title":"Garlic Bread (Bakery-Style)","description":"Crispy, golden garlic bread with a soft buttery center — just like your favorite bakery.","ingredients":["Sliced French bread or white bread loaf","Unsalted butter, softened","Dried parsley, chopped fresh garlic cloves","A pinch of salt"],"directions":["Preheat air fryer to toast mode at 400°F (205°C).","Slice bread evenly on both sides with melted garlic-parsley butter.","Toast for about 6-8 minutes until golden brown and crispy."],"tips":["For extra flavor, add a pinch of Parmesan cheese on top before toasting.","Watch closely during the last minute to avoid burning."]},"es":{"title":"Pan de Ajo Estilo Panadería","description":"Pan de ajo crujiente y dorado con un centro suave y mantecoso — como el de tu panadería favorita.","ingredients":["Pan francés rebanado o pan blanco","Mantequilla sin sal, ablandada","Perejil seco, dientes de ajo fresco picados","Una pizca de sal"],"directions":["Precalentar la freidora a 205°C en modo tostar.","Untar el pan uniformemente con mantequilla de ajo y perejil derretida.","Tostar durante 6-8 minutos hasta que esté dorado y crujiente."],"tips":["Para más sabor, añadir un poco de queso parmesano antes de tostar.","Vigilar de cerca en el último minuto para evitar quemaduras."]},"fr":{"title":"Pain à l Ail Façon Boulangerie","description":"Pain à l ail croustillant et doré avec un cœur tendre au beurre — comme à la boulangerie.","ingredients":["Pain français tranché ou pain blanc","Beurre doux, ramolli","Persil séché, gousses d ail fraîches hachées","Une pincée de sel"],"directions":["Préchauffer la friteuse à 205°C en mode griller.","Tartiner le pain uniformément avec du beurre à l ail et persil fondu.","Griller pendant 6-8 minutes jusqu à ce qu il soit doré et croustillant."],"tips":["Pour plus de goût, ajouter un peu de parmesan avant de griller.","Surveiller de près la dernière minute pour éviter de brûler."]},"ja":{"title":"ガーリックブレッド（ベーカリースタイル）","description":"カリッと黄金色で中心はバターの風味豊か — お気に入りのベーカリーのような味わい。","ingredients":["スライスしたフランスパンまたは白パン","無塩バター（常温に戻す）","乾燥パセリ、刻んだにんにく","塩ひとつまみ"],"directions":["エアフライヤーをトーストモードで400°F（205°C）に予熱する。","溶かしたガーリックパセリバターをパンの両面に均等に塗る。","約6-8分、きつね色になってカリッとするまでトーストする。"],"tips":["風味を増すには、トースト前にパルメザンチーズを少々振りかける。","焦げないよう、最後の1分は注意深く見守る。"]},"pt":{"title":"Pão de Alho Estilo Padaria","description":"Pão de alho crocante e dourado com centro macio e amanteigado — como o da sua padaria favorita.","ingredients":["Pão francês fatiado ou pão branco","Manteiga sem sal, amolecida","Salsinha seca, dentes de alho fresco picados","Uma pitada de sal"],"directions":["Pré-aqueça a fritadeira no modo torrar a 205°C.","Passe a manteiga de alho e salsinha derretida uniformemente nos dois lados do pão.","Torre por cerca de 6-8 minutos até dourar e ficar crocante."],"tips":["Para mais sabor, adicione uma pitada de queijo parmesão antes de torrar.","Observe atentamente no último minuto para evitar queimar."]},"zh":{"title":"烘焙坊级别蒜香面包","description":"外酥里嫩的金黄蒜香面包，黄油香气四溢 — 媲美你最爱的烘焙坊。","ingredients":["法棍面包片或白面包","无盐黄油（室温软化）","干欧芹碎、新鲜蒜末","盐少许"],"directions":["将空气炸锅以吐司模式预热至400°F（205°C）。","将融化的蒜香欧芹黄油均匀涂在面包两面。","烘烤约6-8分钟，至金黄酥脆即可。"],"tips":["想要更香浓，可在烘烤前撒一点帕玛森芝士碎。","最后1分钟盯紧，避免烤焦。"]}}',
     2),
    ('airfryeroven', '🥯', 'Bagel', '420°F (220°C)', '8-10 minutes',
     '{"en":{"title":"Everything Bagel Salmon Melt","description":"An open-faced bagel loaded with cream cheese, smoked salmon, and everything seasoning — brunch perfection.","ingredients":["Everything bagels, halved","Cream cheese, softened","Smoked salmon slices","Red onion, thinly sliced (optional)","Fresh dill (optional)"],"directions":["Slice bagels in half.","Toast bagel halves until golden.","Spread cream cheese on each half.","Layer salmon, onions, and dill on top.","Place assembled bagel halves in the oven and toast until warm and melty."],"tips":["Add capers for extra briny flavor.","Serve immediately while warm."]},"es":{"title":"Bagel Derretido con Salmón","description":"Bagel abierto cargado con queso crema, salmón ahumado y el sazonador everything — perfección para el brunch.","ingredients":["Bagels everything, cortados a la mitad","Queso crema, ablandado","Láminas de salmón ahumado","Cebolla roja, en rodajas finas (opcional)","Eneldo fresco (opcional)"],"directions":["Cortar los bagels a la mitad.","Tostar las mitades hasta que estén doradas.","Untar queso crema en cada mitad.","Colocar el salmón, cebolla y eneldo encima.","Colocar las mitades ensambladas en el horno y tostar hasta que estén calientes y derretidas."],"tips":["Añadir alcaparras para un sabor extra.","Servir inmediatamente mientras esté caliente."]},"fr":{"title":"Bagel Fondant au Saumon","description":"Bagel ouvert garni de fromage frais, saumon fumé et l assaisonnement everything — le brunch parfait.","ingredients":["Bagels everything, coupés en deux","Fromage frais, ramolli","Tranches de saumon fumé","Oignon rouge, émincé finement (optionnel)","Aneth frais (optionnel)"],"directions":["Couper les bagels en deux.","Faire griller les moitiés jusqu à ce qu elles soient dorées.","Tartiner le fromage frais sur chaque moitié.","Disposer le saumon, l oignon et l aneth par-dessus.","Placer les moitiés assemblées dans le four et griller jusqu à ce que ce soit chaud et fondu."],"tips":["Ajouter des câpres pour une saveur salée supplémentaire.","Servir immédiatement pendant que c est chaud."]},"ja":{"title":"エブリシングベーグルサーモンメルト","description":"クリームチーズ、スモークサーモン、エブリシングシーズニングをたっぷり乗せたオープンサンド — ブランチの極み。","ingredients":["エブリシングベーグル（半分に切る）","クリームチーズ（常温に戻す）","スモークサーモンスライス","赤玉ねぎ（薄切り、お好みで）","フレッシュディル（お好みで）"],"directions":["ベーグルを半分に切る。","ベーグルの断面をきつね色になるまでトーストする。","各半分にクリームチーズを塗る。","サーモン、玉ねぎ、ディルを重ねて乗せる。","組み立てたベーグルをオーブンに入れ、温かくチーズが溶けるまでトーストする。"],"tips":["ケーパーを加えると塩気が増して風味がアップ。","温かいうちにすぐに提供する。"]},"pt":{"title":"Bagel Derretido com Salmão","description":"Bagel aberto carregado com cream cheese, salmão defumado e tempero everything — perfeição para o brunch.","ingredients":["Bagels everything, cortados ao meio","Cream cheese, amolecido","Fatias de salmão defumado","Cebola roxa, em fatias finas (opcional)","Endro fresco (opcional)"],"directions":["Corte os bagels ao meio.","Torre as metades até dourar.","Passe cream cheese em cada metade.","Disponha o salmão, cebola e endro por cima.","Coloque as metades montadas no forno e torre até aquecer e derreter."],"tips":["Adicione alcaparras para um sabor salgado extra.","Sirva imediatamente enquanto está quente."]},"zh":{"title":"百吉圈三文鱼熔烤","description":"满满的奶油芝士、烟熏三文鱼和万能调味料铺在开口百吉圈上 — 完美的早午餐。","ingredients":["万能百吉圈（对半切开）","奶油芝士（室温软化）","烟熏三文鱼片","红洋葱（切薄片，可选）","新鲜莳萝（可选）"],"directions":["将百吉圈对半切开。","将百吉圈切面烤至金黄。","在每半边涂上奶油芝士。","铺上三文鱼、洋葱和莳萝。","将组装好的百吉圈放入烤箱，烤至温热芝士融化即可。"],"tips":["加入刺山柑增添咸鲜风味。","趁热立即享用。"]}}',
     3),
    ('airfryeroven', '🍕', 'Pizza', '450°F (230°C)', '10-15 minutes',
     '{"en":{"title":"New York-Style Pizza","description":"Thin, foldable crust with a perfect char — authentic New York pizza made right in your air fryer oven.","ingredients":["Pizza dough (thick-crust style)","Pizza sauce","Shredded mozzarella cheese","Pepperoni (optional)","Dried oregano or red pepper flakes (optional)"],"directions":["Place a pizza stone or baking tray in the oven and preheat thoroughly.","Stretch the dough to fit the pan or stone, shaping it into a round pizza.","Spread sauce evenly over the dough, leaving a small border around the edge.","Top with cheese.","Add pepperoni if desired.","Carefully place the pizza onto the preheated stone or tray.","Bake at 450°F (230°C) for 10-15 minutes.","Remove when the crust is lightly browned and the cheese is melted and bubbling.","Let cool briefly, then slice and serve."],"tips":["For a crispier crust, use a pizza stone and preheat it for at least 15 minutes.","Do not overload with toppings — this can make the pizza soggy.","Let cool for 2-3 minutes before slicing to prevent toppings from sliding off."]},"es":{"title":"Pizza Estilo Nueva York","description":"Masa fina y plegable con un tostado perfecto — auténtica pizza neoyorquina hecha en tu horno freidor de aire.","ingredients":["Masa de pizza (estilo corteza gruesa)","Salsa de pizza","Queso mozzarella rallado","Pepperoni (opcional)","Orégano seco o hojuelas de chile rojo (opcional)"],"directions":["Colocar una piedra para pizza o bandeja en el horno y precalentar bien.","Estirar la masa para que quepa en el molde o piedra, dándole forma redonda.","Extender la salsa uniformemente sobre la masa, dejando un borde pequeño.","Cubrir con queso.","Añadir pepperoni si se desea.","Colocar con cuidado la pizza sobre la piedra o bandeja precalentada.","Hornear a 230°C durante 10-15 minutos.","Retirar cuando el borde esté ligeramente dorado y el queso esté derretido y burbujeando.","Dejar enfriar brevemente, luego cortar y servir."],"tips":["Para una base más crujiente, use una piedra para pizza y precaliéntela al menos 15 minutos.","No ponga demasiados ingredientes — puede humedecer la pizza.","Deje enfriar 2-3 minutos antes de cortar para que los ingredientes no se deslicen."]},"fr":{"title":"Pizza Façon New York","description":"Pâte fine et pliable avec une carbonisation parfaite — authentique pizza new-yorkaise dans votre four friteuse.","ingredients":["Pâte à pizza (style croûte épaisse)","Sauce pizza","Mozzarella râpée","Pepperoni (optionnel)","Origan séché ou flocons de piment rouge (optionnel)"],"directions":["Placer une pierre à pizza ou plaque de cuisson dans le four et bien préchauffer.","Étirer la pâte pour qu elle tienne dans le moule ou sur la pierre, en formant une pizza ronde.","Étaler la sauce uniformément sur la pâte, en laissant une petite bordure.","Recouvrir de fromage.","Ajouter du pepperoni si désiré.","Placer délicatement la pizza sur la pierre ou plaque préchauffée.","Cuire à 230°C pendant 10-15 minutes.","Retirer lorsque la croûte est légèrement dorée et le fromage fondu et bouillonnant.","Laisser refroidir brièvement, puis couper et servir."],"tips":["Pour une croûte plus croustillante, utilisez une pierre à pizza et préchauffez-la au moins 15 minutes.","Ne surchargez pas de garnitures — cela peut rendre la pizza détrempée.","Laisser refroidir 2-3 minutes avant de couper pour éviter que les garnitures ne glissent."]},"ja":{"title":"ニューヨークスタイルピザ","description":"薄く折りたためる生地に完璧な焦げ目 — エアフライヤーオーブンで作る本格NYピザ。","ingredients":["ピザ生地（厚めクラスト用）","ピザソース","モッツァレラチーズ（細切り）","ペパロニ（お好みで）","乾燥オレガノまたは赤唐辛子フレーク（お好みで）"],"directions":["ピザストーンまたは天板をオーブンに入れ、十分に予熱する。","生地をパンやストーンに合わせて伸ばし、丸いピザの形に整える。","生地の上にソースを均等に塗り、縁を少し残す。","チーズをトッピングする。","お好みでペパロニを追加する。","予熱したストーンまたは天板にピザを慎重に置く。","450°F（230°C）で10-15分焼く。","生地がほんのり焼け、チーズが溶けて泡立ってきたら取り出す。","少し冷ましてから切り分けて提供する。"],"tips":["よりカリッとした生地にするには、ピザストーンを使い15分以上予熱する。","具材を乗せすぎない — ピザがべちゃっとします。","切る前に2-3分冷ますと具材が滑り落ちません。"]},"pt":{"title":"Pizza Estilo Nova York","description":"Massa fina e dobrável com uma carbonização perfeita — pizza autêntica de Nova York feita no seu forno fritadeira.","ingredients":["Massa de pizza (estilo crosta grossa)","Molho de pizza","Queijo mussarela ralado","Pepperoni (opcional)","Orégano seco ou flocos de pimenta vermelha (opcional)"],"directions":["Coloque uma pedra para pizza ou assadeira no forno e pré-aqueça bem.","Estique a massa para caber na forma ou pedra, moldando-a em pizza redonda.","Espalhe o molho uniformemente sobre a massa, deixando uma pequena borda.","Cubra com queijo.","Adicione pepperoni se desejar.","Coloque cuidadosamente a pizza na pedra ou assadeira pré-aquecida.","Asse a 230°C por 10-15 minutos.","Retire quando a crosta estiver levemente dourada e o queijo derretido e borbulhando.","Deixe esfriar brevemente, depois corte e sirva."],"tips":["Para uma crosta mais crocante, use uma pedra para pizza e pré-aqueça por pelo menos 15 minutos.","Não sobrecarregue com coberturas — isso pode deixar a pizza encharcada.","Deixe esfriar por 2-3 minutos antes de cortar para evitar que as coberturas deslizem."]},"zh":{"title":"纽约风格披萨","description":"薄而柔韧的饼底，恰到好处的焦香 — 用空气炸烤箱做出的正宗纽约披萨。","ingredients":["披萨面团（厚底风格）","披萨酱","马苏里拉芝士碎","意式辣香肠（可选）","干牛至叶或红椒碎（可选）"],"directions":["将披萨石或烤盘放入烤箱，充分预热。","将面团拉伸至适合烤盘或石板的大小，做成圆形披萨。","在面团上均匀涂抹酱料，边缘留一圈空白。","撒上芝士。","可按喜好添加辣香肠。","小心将披萨放上预热好的石板或烤盘。","以450°F（230°C）烘烤10-15分钟。","当饼底微微上色、芝士融化冒泡时取出。","稍微冷却后切片享用。"],"tips":["想要更酥脆的饼底，使用披萨石并预热至少15分钟。","不要堆太多配料 — 会让披萨变得湿软。","切片前冷却2-3分钟，避免配料滑落。"]}}',
     4),
    ('airfryeroven', '🥧', 'Bake', '350°F (175°C)', '40-45 minutes',
     '{"en":{"title":"Chicken Pot Pie","description":"Creamy chicken and vegetable filling wrapped in golden flaky pastry — the ultimate comfort food.","ingredients":["Cooked chicken, diced or shredded","Mixed vegetables (peas, carrots, corn)","Chicken broth — 1 cup","Onion, finely diced — ½ medium","Unsalted butter — 2 tbsp (28 g)","All-purpose flour — 2 tbsp (16 g)","Milk or cream — ¾ cup (180 ml)","Salt, black pepper — to taste","Puff pastry sheet or pie crust","Egg wash (for top crust only)"],"directions":["Preheat the oven to 350°F (175°C).","Sauté onion in butter until soft.","Stir in flour to make a roux.","Gradually whisk in broth and milk, simmering until thickened.","Add chicken and vegetables, season well.","Pour filling into baking dish, cover with pastry/crust.","Brush with egg wash, cut vents.","Bake 40-45 minutes until golden and bubbly."],"tips":["Let cool slightly before serving; the filling will be very hot.","Use leftover turkey instead of chicken for variety."]},"es":{"title":"Pastel de Pollo","description":"Relleno cremoso de pollo y verduras envuelto en masa hojaldrada dorada — la comida reconfortante por excelencia.","ingredients":["Pollo cocido, en cubos o desmenuzado","Verduras mixtas (chícharos, zanahorias, maíz)","Caldo de pollo — 1 taza","Cebolla, finamente picada — ½ mediana","Mantequilla sin sal — 2 cdas (28 g)","Harina de trigo — 2 cdas (16 g)","Leche o crema — ¾ taza (180 ml)","Sal, pimienta negra — al gusto","Masa de hojaldre o corteza para pastel","Huevo batido (solo para la capa superior)"],"directions":["Precalentar el horno a 175°C.","Sofreír la cebolla en mantequilla hasta que esté blanda.","Agregar la harina y revolver para hacer un roux.","Incorporar gradualmente el caldo y la leche, hirviendo a fuego lento hasta que espese.","Agregar el pollo y las verduras, sazonar bien.","Verter el relleno en una fuente para hornear, cubrir con la masa.","Cepillar con el huevo batido, cortar ventilaciones.","Hornear 40-45 minutos hasta que esté dorado y burbujeante."],"tips":["Deje enfriar ligeramente antes de servir; el relleno estará muy caliente.","Use pavo sobrante en lugar de pollo para variar."]},"fr":{"title":"Tourte au Poulet","description":"Garniture crémeuse au poulet et légumes enveloppée dans une pâte feuilletée dorée — le plat réconfort ultime.","ingredients":["Poulet cuit, en dés ou effiloché","Légumes mélangés (petits pois, carottes, maïs)","Bouillon de poulet — 1 tasse","Oignon, finement coupé en dés — ½ moyen","Beurre doux — 2 càs (28 g)","Farine tout usage — 2 càs (16 g)","Lait ou crème — ¾ tasse (180 ml)","Sel, poivre noir — au goût","Pâte feuilletée ou croûte à tarte","Dorure à l œuf (pour la croûte supérieure uniquement)"],"directions":["Préchauffer le four à 175°C.","Faire revenir l oignon dans le beurre jusqu à ce qu il soit tendre.","Incorporer la farine pour faire un roux.","Ajouter progressivement le bouillon et le lait en fouettant, laisser mijoter jusqu à épaississement.","Ajouter le poulet et les légumes, bien assaisonner.","Verser la garniture dans un plat, couvrir de pâte.","Badigeonner à l œuf, faire des évents.","Cuire 40-45 minutes jusqu à ce que ce soit doré et bouillonnant."],"tips":["Laisser refroidir légèrement avant de servir; la garniture sera très chaude.","Utilisez de la dinde pour varier."]},"ja":{"title":"チキンポットパイ","description":"クリーミーな鶏肉と野菜のフィリングをサクサクのパイ生地で包んだ — 究極のコンフォートフード。","ingredients":["調理済み鶏肉（角切りまたはほぐし）","ミックスベジタブル（グリーンピース、ニンジン、コーン）","チキンブロス — 1カップ","玉ねぎ（みじん切り）— ½個","無塩バター — 大さじ2（28g）","薄力粉 — 大さじ2（16g）","牛乳または生クリーム — ¾カップ（180ml）","塩、黒コショウ — 適量","パイシートまたはパイクラスト","卵液（上面のみ）"],"directions":["オーブンを350°F（175°C）に予熱する。","バターで玉ねぎを炒め柔らかくする。","小麦粉を加えてルーを作る。","ブロスとミルクを少しずつ加えて混ぜ、とろみがつくまで煮る。","鶏肉と野菜を加え、しっかり味付けする。","フィリングを焼き皿に注ぎ、パイ生地で覆う。","卵液を塗り、蒸気口を切る。","40-45分、きつね色で泡立つまで焼く。"],"tips":["提供前に少し冷ます；フィリングがとても熱くなっています。","バリエーションとして残った七面鳥でも代用可。"]},"pt":{"title":"Torta de Frango","description":"Recheio cremoso de frango e legumes envolto em massa folhada dourada — a melhor comida reconfortante.","ingredients":["Frango cozido, em cubos ou desfiado","Legumes mistos (ervilhas, cenouras, milho)","Caldo de galinha — 1 xícara","Cebola, finamente picada — ½ média","Manteiga sem sal — 2 colheres de sopa (28 g)","Farinha de trigo — 2 colheres de sopa (16 g)","Leite ou creme — ¾ xícara (180 ml)","Sal, pimenta preta — a gosto","Massa folhada ou crosta de torta","Ovo batido (apenas para a crosta superior)"],"directions":["Pré-aqueça o forno a 175°C.","Refogue a cebola na manteiga até ficar macia.","Adicione a farinha e mexa para fazer um roux.","Incorpore gradualmente o caldo e o leite, cozinhando até engrossar.","Adicione o frango e os legumes, tempere bem.","Despeje o recheio na travessa, cubra com a massa.","Pincele com ovo batido, faça aberturas para ventilação.","Asse por 40-45 minutos até dourar e borbulhar."],"tips":["Deixe esfriar um pouco antes de servir; o recheio estará muito quente.","Use peru no lugar do frango para variar."]},"zh":{"title":"鸡肉馅饼","description":"浓郁奶油鸡肉蔬菜馅，包裹在金黄的酥皮中 — 最治愈的暖心美食。","ingredients":["熟鸡肉 切丁或撕碎","混合蔬菜（豌豆、胡萝卜、玉米）","鸡汤 1杯","洋葱 半个（切细丁）","无盐黄油 2汤匙（28克）","中筋面粉 2汤匙（16克）","牛奶或奶油 3/4杯（180毫升）","盐、黑胡椒 适量","千层酥皮或派皮","蛋液（仅表面）"],"directions":["烤箱预热至350°F（175°C）。","黄油炒香洋葱至透明。","加入面粉搅拌制成面糊。","逐步加入鸡汤和牛奶，搅匀煮至浓稠。","加入鸡肉和蔬菜，调味。","将馅料倒入烤盘，盖上酥皮。","刷蛋液，划开排气口。","烤40-45分钟，至表面金黄、馅料冒泡即可。"],"tips":["食用前稍微冷却，馅料非常烫。","用剩下的火鸡肉代替鸡肉换换口味。"]}}',
     5),
    ('airfryeroven', '🍗', 'Roast', '375°F (190°C)', '60-65 minutes',
     '{"en":{"title":"Roast Chicken with Root Vegetables","description":"Juicy whole roast chicken surrounded by tender root vegetables — a complete family dinner.","ingredients":["Whole chicken (4-6 lb / 1.8-2.7 kg)","Potatoes, cubed (large) — 3 cups","Carrots, chopped — 2 cups","Red onion, quartered — 1 large","Olive oil — 3 tbsp","Salt — 1 tsp","Black pepper — 1 tsp","Garlic powder (or fresh garlic) — 1 tsp","Dried herbs (rosemary/thyme) — 1 tsp"],"directions":["Rinse the seasoned chicken inside and out, pat dry.","Rub olive oil and seasonings all over the chicken skin.","Stuff cavity with lemon halves and herb sprigs if desired.","Place chicken breast-side up in roasting pan.","Surround with root vegetables, toss them in oil and seasoning.","Roast at 375°F (190°C) for 60-65 min until internal temp reaches 165°F (74°C).","Rest for 10 minutes before carving."],"tips":["Use a meat thermometer for accuracy.","Let rest before slicing for juicy results."]},"es":{"title":"Pollo Asado con Verduras de Raíz","description":"Pollo asado jugoso entero rodeado de tiernas verduras de raíz — una cena familiar completa.","ingredients":["Pollo entero (4-6 lb / 1.8-2.7 kg)","Papas, en cubos (grandes) — 3 tazas","Zanahorias, picadas — 2 tazas","Cebolla roja, en cuartos — 1 grande","Aceite de oliva — 3 cdas","Sal — 1 cdta","Pimienta negra — 1 cdta","Ajo en polvo (o ajo fresco) — 1 cdta","Hierbas secas (romero/tomillo) — 1 cdta"],"directions":["Enjuagar el pollo por dentro y por fuera, secar.","Frotar el aceite de oliva y los sazonadores sobre toda la piel del pollo.","Rellenar la cavidad con medias limas y ramitas de hierbas si se desea.","Colocar el pollo con el pecho hacia arriba en la bandeja de asar.","Rodear con las verduras de raíz, revolver con aceite y sazonador.","Asar a 190°C durante 60-65 minutos hasta que la temperatura interna alcance 74°C.","Reposar 10 minutos antes de cortar."],"tips":["Use un termómetro de carne para precisión.","Deje reposar antes de cortar para resultados jugosos."]},"fr":{"title":"Poulet Rôti aux Légumes Racines","description":"Un poulet rôti entier juteux entouré de tendres légumes racines — un dîner familial complet.","ingredients":["Poulet entier (1.8-2.7 kg)","Pommes de terre, en cubes (gros) — 3 tasses","Carottes, hachées — 2 tasses","Oignon rouge, en quartiers — 1 gros","Huile d olive — 3 càs","Sel — 1 càc","Poivre noir — 1 càc","Ail en poudre (ou ail frais) — 1 càc","Herbes séchées (romarin/thym) — 1 càc"],"directions":["Rincer le poulet assaisonné à l intérieur et à l extérieur, sécher.","Frotter l huile d olive et les assaisonnements sur toute la peau du poulet.","Farcir la cavité avec des demi-citrons et des brins d herbes si désiré.","Placer le poulet, poitrine vers le haut, dans le plat à rôtir.","Entourer de légumes racines, les enrober d huile et d assaisonnement.","Rôtir à 190°C pendant 60-65 min jusqu à ce que la température interne atteigne 74°C.","Laisser reposer 10 minutes avant de découper."],"tips":["Utilisez un thermomètre à viande pour plus de précision.","Laissez reposer avant de trancher pour des résultats juteux."]},"ja":{"title":"根菜とローストチキン","description":"ジューシーな丸ごとローストチキンを柔らかな根菜が囲む — 家族全員が満足するディナー。","ingredients":["丸鶏（1.8-2.7 kg）","じゃがいも（大きめの角切り）— 3カップ","にんじん（乱切り）— 2カップ","赤玉ねぎ（くし形切り）— 大1個","オリーブオイル — 大さじ3","塩 — 小さじ1","黒コショウ — 小さじ1","ガーリックパウダー（または生にんにく）— 小さじ1","ドライハーブ（ローズマリー/タイム）— 小さじ1"],"directions":["鶏の内側と外側を洗い、水気を拭く。","オリーブオイルと調味料を鶏の皮全体にすり込む。","お好みでレモン半切れとハーブの小枝を詰める。","鶏を胸を上にしてローストパンに置く。","根菜を周りに並べ、油と調味料を絡める。","375°F（190°C）で60-65分、内部温度が165°F（74°C）に達するまで焼く。","切り分ける前に10分休ませる。"],"tips":["正確さのために肉用温度計を使用。","ジューシーに仕上げるためにスライス前に休ませる。"]},"pt":{"title":"Frango Assado com Legumes de Raiz","description":"Frango assado inteiro e suculento rodeado por legumes de raiz macios — um jantar familiar completo.","ingredients":["Frango inteiro (1.8-2.7 kg)","Batatas, em cubos (grandes) — 3 xícaras","Cenouras, picadas — 2 xícaras","Cebola roxa, em quartos — 1 grande","Azeite de oliva — 3 colheres de sopa","Sal — 1 colher de chá","Pimenta preta — 1 colher de chá","Alho em pó (ou alho fresco) — 1 colher de chá","Ervas secas (alecrim/tomilho) — 1 colher de chá"],"directions":["Enxágue o frango temperado por dentro e por fora, seque.","Esfregue azeite e temperos por toda a pele do frango.","Recheie a cavidade com metades de limão e ramos de ervas se desejar.","Coloque o frango com o peito para cima na assadeira.","Cerque com legumes de raiz, envolvendo-os em azeite e tempero.","Asse a 190°C por 60-65 minutos até que a temperatura interna atinja 74°C.","Descanse por 10 minutos antes de cortar."],"tips":["Use um termômetro de carne para precisão.","Deixe descansar antes de fatiar para resultados suculentos."]},"zh":{"title":"烤全鸡配根茎蔬菜","description":"整只鲜嫩多汁的烤鸡，配上香甜的根茎蔬菜 — 一顿完美的家庭大餐。","ingredients":["整鸡（4-6磅 / 1.8-2.7公斤）","土豆（大块）3杯","胡萝卜（切段）2杯","红洋葱（切块）1大个","橄榄油 3汤匙","盐 1茶匙","黑胡椒 1茶匙","蒜粉（或新鲜大蒜）1茶匙","干香草（迷迭香/百里香）1茶匙"],"directions":["将鸡内外冲洗干净，擦干水分。","在鸡皮表面均匀涂抹橄榄油和调味料。","可在腹腔内塞入柠檬片和香草枝增加风味。","将鸡胸朝上放入烤盘。","周围放上根茎蔬菜，淋油调味拌匀。","以375°F（190°C）烤制60-65分钟，至鸡肉内部温度达165°F（74°C）。","取出静置10分钟后再切块。"],"tips":["使用肉类温度计确保精准。","切前静置片刻，能保持肉汁丰富。"]}}',
     6),
